const item = $input.first().json;
let data = null;
if (item && (item.nodes || item.connections)) { data = item; }
if (!data && item) {
  let raw = item.content || item.text || item.output || item.message || item.response || '';
  if (typeof raw === 'object' && raw !== null) { data = raw; }
  else { raw = (raw || '').toString(); try { data = JSON.parse(raw); } catch (e) { const s = raw.indexOf('{'); const en = raw.lastIndexOf('}'); data = (s !== -1 && en > s) ? (function(){ try { return JSON.parse(raw.slice(s, en + 1)); } catch (e2) { return {}; } })() : {}; } }
}
data = data || {};
function uuid(){ return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ var r = Math.random()*16|0; var v = c === 'x' ? r : (r&0x3|0x8); return v.toString(16); }); }
let nodes = Array.isArray(data.nodes) ? data.nodes : [];
nodes = nodes.filter(function(n){ return n && n.type && n.name; });
nodes = nodes.map(function(n, i){ return { parameters: (n.parameters && typeof n.parameters === 'object') ? n.parameters : {}, type: n.type, typeVersion: (typeof n.typeVersion === 'number') ? n.typeVersion : 1, position: Array.isArray(n.position) ? n.position : [i*240, 0], id: n.id || uuid(), name: n.name }; });
const connections = (data.connections && typeof data.connections === 'object') ? data.connections : {};
const nm = ($('Receive Build Request').first().json.name || '').toString().trim();
const body = { name: nm ? nm : (data.name || 'Generated Workflow'), nodes: nodes, connections: connections, settings: {} };
return [{ json: { body: body, node_count: nodes.length } }];

const resp = $json;
const id = resp.id || (resp.data && resp.data.id) || '';
if (id) {
  return [{ json: { success: true, id: id, name: resp.name || '', active: resp.active === true, url: 'https://YOUR_N8N_DOMAIN/workflow/' + id, message: 'Workflow created and left INACTIVE. Review it in n8n, then activate it when ready.' } }];
}
return [{ json: { success: false, error: resp.message || resp.error || resp, hint: 'Not created. Check that node types and typeVersions are from the allowed list and that only name, nodes, connections, settings were sent.' } }];

const inp = $('Receive Build Request').first().json;
const a = (inp.action || '').toString();
const wid = (inp.workflow_id || '').toString();
const eid = (inp.execution_id || '').toString();
const base = 'https://YOUR_N8N_DOMAIN/api/v1';
let method = 'GET';
let url = base + '/workflows';
if (a === 'list_workflows') { method = 'GET'; url = base + '/workflows?limit=100'; }
else if (a === 'get_workflow') { method = 'GET'; url = base + '/workflows/' + wid; }
else if (a === 'activate_workflow') { method = 'POST'; url = base + '/workflows/' + wid + '/activate'; }
else if (a === 'deactivate_workflow') { method = 'POST'; url = base + '/workflows/' + wid + '/deactivate'; }
else if (a === 'list_executions') { method = 'GET'; url = base + '/executions?limit=20' + (wid ? ('&workflowId=' + wid) : ''); }
else if (a === 'get_execution') { method = 'GET'; url = base + '/executions/' + eid + '?includeData=true'; }
return [{ json: { method: method, url: url, action: a } }];

const action = ($('Receive Build Request').first().json.action || '').toString();
const resp = $json;
if (action === 'list_workflows') {
  const arr = Array.isArray(resp.data) ? resp.data : [];
  return [{ json: { count: arr.length, workflows: arr.map(w => ({ id: w.id, name: w.name, active: w.active })), nextCursor: resp.nextCursor || null } }];
}
if (action === 'list_executions') {
  const arr = Array.isArray(resp.data) ? resp.data : [];
  return [{ json: { count: arr.length, executions: arr.map(e => ({ id: e.id, workflowId: e.workflowId, status: e.status, startedAt: e.startedAt, stoppedAt: e.stoppedAt, finished: e.finished })), nextCursor: resp.nextCursor || null } }];
}
return [{ json: resp }];
